const collectionMock = jest.fn();
const addMock = jest.fn();
const updateMock = jest.fn();
const getMock = jest.fn();
const docMock = jest.fn();

jest.mock('@/lib/server/firebase-admin', () => ({
  adminDb: { collection: (...args: unknown[]) => collectionMock(...args) },
}));

jest.mock('firebase-admin/firestore', () => ({
  Timestamp: { now: jest.fn(() => 'ts') },
}));

import { POST } from '@/app/api/leads/request-viewing/route';

const makeReq = (body: unknown) =>
  new Request('http://localhost:3000/api/leads/request-viewing', {
    method: 'POST',
    body: JSON.stringify(body),
  });

describe('POST /api/leads/request-viewing', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    docMock.mockReturnValue({ update: updateMock, get: getMock });
    collectionMock.mockReturnValue({ add: addMock, doc: docMock });
    addMock.mockResolvedValue({ id: 'viewing-abc' });
    updateMock.mockResolvedValue(undefined);
    getMock.mockResolvedValue({ exists: true });
  });

  test('creates viewing request with valid payload', async () => {
    const res = await POST(makeReq({ leadId: 'lead-1', unitId: 'unit-1' }));
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body.success).toBe(true);
    expect(body.viewingId).toBe('viewing-abc');
  });

  test('returns 400 when leadId is missing', async () => {
    const res = await POST(makeReq({ unitId: 'unit-1' }));
    const body = await res.json();

    expect(res.status).toBe(400);
    expect(body.error).toBeDefined();
    expect(addMock).not.toHaveBeenCalled();
  });

  test('returns 400 when unitId is missing', async () => {
    const res = await POST(makeReq({ leadId: 'lead-1' }));
    const body = await res.json();

    expect(res.status).toBe(400);
    expect(body.error).toBeDefined();
    expect(addMock).not.toHaveBeenCalled();
  });

  test('returns 400 when body is empty', async () => {
    const res = await POST(makeReq({}));
    const body = await res.json();

    expect(res.status).toBe(400);
    expect(addMock).not.toHaveBeenCalled();
  });

  test('accepts optional portfolioId', async () => {
    const res = await POST(makeReq({ leadId: 'l1', unitId: 'u1', portfolioId: 'p1' }));
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body.success).toBe(true);
  });
});

import { NextResponse } from 'next/server';

export async function POST(req: Request) {
  try {
    const { leadId, units } = await req.json();

    // const notifier = new TelegramNotifier();
    // const scheduler = new GoogleCalendarScheduler();

    // Mocking DB lookup
    const clientEmail = `client_${leadId}@example.com`;
    const clientName = `Client ${leadId}`;
    const agentEmail = `agent@sierraestates.com`;
    const agentName = `Sierra Agent`;
    
    // We schedule it for tomorrow at 10 AM by default
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    tomorrow.setHours(10, 0, 0, 0);

    const propertyTitles = units.map((u: any) => u.title);

    // Trigger Google Calendar
    const calendarLink = `https://calendar.google.com/calendar/u/0/r/eventedit?text=Viewing+${encodeURIComponent(propertyTitles.join(', '))}`;

    // Trigger Telegram Notification to Team
    // await notifier.sendViewingScheduledAlert(agentName, clientName, propertyTitles, tomorrow.toLocaleString());

    return NextResponse.json({ 
      success: true, 
      calendarLink,
      message: 'Viewing scheduled and team notified successfully.'
    });
  } catch (error: any) {
    console.error('Error scheduling viewing:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { initializeApp, cert } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';
import * as dotenv from 'dotenv';
import { resolve } from 'path';

dotenv.config({ path: resolve(process.cwd(), '.env') });

// Ensure you have FIREBASE_SERVICE_ACCOUNT_KEY in your .env
let serviceAccount;
try {
  serviceAccount = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT_KEY || '{}');
} catch (e) {
  console.error("Missing or invalid FIREBASE_SERVICE_ACCOUNT_KEY in .env");
  process.exit(1);
}

initializeApp({
  credential: cert(serviceAccount)
});

const db = getFirestore();

const COMPOUNDS_21 = [
  "Uptown Cairo", "Mivida", "Marassi", "Hyde Park", "Palm Hills New Cairo", 
  "Mountain View iCity", "Villette", "ZED East", "Taj City", "Sarai", 
  "District 5", "Eastown", "The Brooks", "Stone Residence", "Swan Lake Residences",
  "Cairo Gate", "Al Burouj", "O West", "Badya", "Silversands", "Hacienda Bay"
];

async function bootstrapMemory() {
  console.log("⚡ Initiating Sierra Estates Vector Knowledge Core...");
  const memoryRef = db.collection('intelligence').doc('global_memory_core');
  
  const payload = {
    version: "1.0",
    lastSyncedAt: new Date(),
    compounds: COMPOUNDS_21,
    syncRules: {
      propertyFinder: {
        frequency: "hourly",
        strictMode: true,
        overwriteLocal: false
      }
    },
    systemDirectives: "You are the central intelligence hub for Sierra Estates."
  };

  await memoryRef.set(payload, { merge: true });
  console.log("✅ Knowledge Core successfully seeded into Firestore.");
  process.exit(0);
}

bootstrapMemory().catch(console.error);

"use client";
import React, { useState, useEffect } from 'react';
import { useAuth } from '../../lib/AuthContext';
import dynamic from 'next/dynamic';
import { motion, AnimatePresence } from 'framer-motion';
import Topbar from '../UI/Topbar';
import Sidebar from '../UI/Sidebar';
import { useRouter } from 'next/navigation';
import { useI18n } from '../../lib/I18nContext';

// Admin specific screens
const AdminDashboard = dynamic(() => import('./AdminDashboard'), { ssr: false });
const TeamCRM = dynamic(() => import('./TeamCRM'), { ssr: false });
const PortfolioAssets = dynamic(() => import('./PortfolioAssets'), { ssr: false });
const IntegrationHub = dynamic(() => import('../Operations/IntegrationHub'), { ssr: false });
const MarketIntelligence = dynamic(() => import('../Operations/MarketIntelligence'), { ssr: false });
const DatabaseExplorer = dynamic(() => import('./DatabaseExplorer'), { ssr: false });

type AdminScreen = 'dashboard' | 'team-crm' | 'listings' | 'nexus' | 'intelligence' | 'media' | 'database';

export default function AdminPortal() {
  const { user, signOut } = useAuth();
  const { locale, t } = useI18n();
  const router = useRouter();
  const [activeScreen, setActiveScreen] = useState<AdminScreen>('dashboard');
  const [direction, setDirection] = useState(1); // 1 for forward, -1 for backward

  const [mounted, setMounted] = useState(false);
  const [greeting, setGreeting] = useState('Welcome');
  const [dateString, setDateString] = useState('');

  useEffect(() => {
    setMounted(true);
    const hour = new Date().getHours();
    const greetKey = hour < 12 ? 'morning' : hour < 18 ? 'afternoon' : 'evening';
    setGreeting(t(`dashboard.${greetKey}`));
    setDateString(new Date().toLocaleDateString(undefined, { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    }));
  }, []);

  if (!mounted) return null;

  const displayName = user?.displayName || user?.email?.split('@')[0] || 'Admin';
  const initials = displayName.split(' ').map((n: string) => n[0]).join('').slice(0, 2).toUpperCase();
  const firstName = displayName.split(' ')[0];

  const handleNavigate = (screen: AdminScreen) => {
    setActiveScreen(screen);
  };

  const handleSignOut = async () => {
    try {
      await signOut();
      router.push('/admin/login');
    } catch (error) {
      console.error('Sign out error:', error);
    }
  };

  return (
    <div className="screen active admin-portal" dir={locale === 'ar' ? 'rtl' : 'ltr'}>
      <Topbar
        onHomeClick={() => setActiveScreen('dashboard')}
        onSignOut={handleSignOut}
        userInitials={initials}
        displayName={`${displayName} (${t('common.admin') || 'Admin'})`}
        isGuest={false}
      />

      <div className="app-layout">
        {/* We can use the same Sidebar but with a restricted set of items if needed, 
            but for now, we'll use a specialized version or the existing one with a prop */}
        <Sidebar 
          activeScreen={activeScreen as any} 
          onNavigate={handleNavigate as any} 
          displayName={displayName}
          userInitials={initials}
        />

        <AnimatePresence mode="wait">
          <motion.div 
            key={activeScreen}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] as [number, number, number, number] }}
            className="main-content"
          >
            {activeScreen === 'dashboard' && (
              <AdminDashboard 
                greeting={greeting}
                firstName={firstName}
                dateString={dateString}
              />
            )}

            {activeScreen === 'team-crm' && <TeamCRM />}
            {activeScreen === 'listings' && <PortfolioAssets />}
            {activeScreen === 'nexus' && <IntegrationHub />}
            {activeScreen === 'intelligence' && <MarketIntelligence />}
            {activeScreen === 'database' && <DatabaseExplorer />}
          </motion.div>
        </AnimatePresence>
      </div>

      <style>{`
        .admin-portal {
          background: #050B14;
        }
        .luxury-accent {
          border-left: 4px solid var(--gold);
        }
      `}</style>
    </div>
  );
}

"use client";
import React, { useState, useEffect } from 'react';
import { storage } from '@/lib/firebase';
import { 
  ref, 
  uploadBytesResumable, 
  getDownloadURL, 
  listAll, 
  deleteObject 
} from 'firebase/storage';
import { useI18n } from '@/lib/I18nContext';

export default function MediaHub() {
  const { t, locale } = useI18n();
  const [files, setFiles] = useState<{name: string, url: string, fullPath: string}[]>([]);
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);

  const fetchMedia = async () => {
    const listRef = ref(storage, 'property-media');
    try {
      const res = await listAll(listRef);
      const fileData = await Promise.all(
        res.items.map(async (item) => ({
          name: item.name,
          url: await getDownloadURL(item),
          fullPath: item.fullPath
        }))
      );
      setFiles(fileData);
    } catch (err) {
      console.error("Media retrieval failed:", err);
    }
  };

  useEffect(() => {
    fetchMedia();
  }, []);

  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploading(true);
    const storageRef = ref(storage, `property-media/${Date.now()}-${file.name}`);
    const uploadTask = uploadBytesResumable(storageRef, file);

    uploadTask.on('state_changed', 
      (snapshot) => {
        const p = (snapshot.bytesTransferred / snapshot.totalBytes) * 100;
        setProgress(p);
      }, 
      (error) => {
        console.error(error);
        setUploading(false);
      }, 
      () => {
        getDownloadURL(uploadTask.snapshot.ref).then(() => {
          setUploading(false);
          setProgress(0);
          fetchMedia();
        });
      }
    );
  };

  const handleDelete = async (fullPath: string) => {
    if (!confirm("Are you sure you want to delete this asset?")) return;
    try {
      await deleteObject(ref(storage, fullPath));
      fetchMedia();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="media-hub animate-fade-in-up">
      <div className="page-header" style={{ marginBottom: '40px' }}>
        <h1 className="serif text-3xl mb-2 gold-underline">{locale === 'ar' ? 'مكتبة الوسائط' : 'Luxury Asset Media Hub'}</h1>
        <p className="text-secondary text-sm">Secure orchestration of high-resolution architectural imagery and portfolio visualizations</p>
      </div>

      <div className="upload-dock glass-panel p-8 mb-12 border-dashed border-2 border-white/10 hover:border-gold/30 transition-all flex flex-col items-center justify-center text-center">
        <input 
          type="file" 
          id="media-upload" 
          className="hidden" 
          onChange={handleUpload}
          accept="image/*"
          disabled={uploading}
        />
        <label htmlFor="media-upload" className="cursor-pointer">
          <div className="w-16 h-16 rounded-full bg-gold/10 flex items-center justify-center text-2xl text-gold mb-4 mx-auto">
            {uploading ? '⏳' : '📤'}
          </div>
          <h3 className="text-lg font-bold text-white mb-2">{uploading ? `Uploading... ${Math.round(progress)}%` : (locale === 'ar' ? 'رفع أصل جديد' : 'Upload Strategic Asset')}</h3>
          <p className="text-xs text-secondary opacity-50 uppercase tracking-widest">{locale === 'ar' ? 'اسحب الملفات هنا أو انقر للإضافة' : 'Drag & Drop architectural assets or click to authorize'}</p>
        </label>
        
        {uploading && (
          <div className="w-full max-w-md bg-white/5 h-1 rounded-full mt-6 overflow-hidden">
            <div className="h-full bg-gold transition-all duration-300" style={{ width: `${progress}%` }}></div>
          </div>
        )}
      </div>

      <div className="media-grid grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6">
        {files.map((file, idx) => (
          <div key={idx} className="media-card group relative aspect-square rounded-2xl overflow-hidden border border-white/5 bg-white/5 hover:border-gold/30 transition-all shadow-xl">
            <img src={file.url} alt={file.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
            <div className="overlay absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-3">
              <button 
                className="p-2 bg-red-500/20 text-red-500 hover:bg-red-500 hover:text-white rounded-full transition-all"
                onClick={() => handleDelete(file.fullPath)}
              >
                🗑️
              </button>
              <div className="text-[10px] text-white/50 px-4 text-center truncate w-full">{file.name}</div>
            </div>
          </div>
        ))}
      </div>

      <style>{`
        .gold-underline {
          position: relative;
          display: inline-block;
        }
        .gold-underline::after {
          content: '';
          position: absolute;
          bottom: -4px;
          left: 0;
          width: 40px;
          height: 2px;
          background: var(--gold);
        }
      `}</style>
    </div>
  );
}

"use client";
import React, { useState } from 'react';
import { useProperties, usePropertyStats } from '../../hooks/useProperties';
import { 
  Property, 
  addProperty, 
  updateProperty, 
  deleteProperty, 
  PropertyStatus, 
  OfferType 
} from '../../lib/firebase/inventory';
import { 
  Plus, 
  MapPin,
  Search, 
  Import, 
  MoreHorizontal, 
  Star, 
  Clock, 
  LayoutGrid, 
  List,
  Package,
  CheckCircle2
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import PropertyForm from './PropertyForm';
import PropertyDrawer from './PropertyDrawer';
import PasteUnit from './PasteUnit';
import toast from 'react-hot-toast';

export default function PortfolioAssets() {
  const [filters, setFilters] = useState({ 
    search: '', 
    status: '' as PropertyStatus | '', 
    offer_type: '' as OfferType | '' 
  });
  
  const { properties, loading, refetch } = useProperties({
    status: filters.status || undefined,
    offer_type: filters.offer_type || undefined
  });

  const { stats, loading: statsLoading } = usePropertyStats();

  const [selectedProperty, setSelectedProperty] = useState<Property | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPasteOpen, setIsPasteOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | undefined>(undefined);

  // Filtered properties (local search)
  const filteredProperties = properties.filter(p => {
    const s = filters.search.toLowerCase();
    return (
      p.title_en.toLowerCase().includes(s) || 
      p.title_ar.toLowerCase().includes(s) || 
      p.unit_code.toLowerCase().includes(s) ||
      p.compound_name.toLowerCase().includes(s)
    );
  });

  const handleCreate = async (data: Partial<Property>) => {
    try {
      await addProperty(data as any);
      toast.success("Asset successfully incorporated into portfolio.");
      setIsFormOpen(false);
      setIsPasteOpen(false);
      refetch();
    } catch (err) {
      toast.error("Failed to synchronize asset data.");
    }
  };

  const handleUpdate = async (data: Partial<Property>) => {
    if (!editingProperty?.id) return;
    try {
      await updateProperty(editingProperty.id, data);
      toast.success("Asset intelligence updated.");
      setIsFormOpen(false);
      setEditingProperty(undefined);
      refetch();
    } catch (err) {
      toast.error("Update synchronization failed.");
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure? This action will permanently remove the asset from the strategic inventory.")) return;
    try {
      await deleteProperty(id);
      toast.success("Asset removed from portfolio.");
      setSelectedProperty(null);
      refetch();
    } catch (err) {
      toast.error("Asset termination failed.");
    }
  };

  const getStatusColor = (status: PropertyStatus) => {
    switch (status) {
      case 'available': return '#22C55E';
      case 'reserved': return '#F59E0B';
      case 'sold': return '#EF4444';
      default: return '#64748B';
    }
  };

  return (
    <div className="portfolio-container p-8 max-w-[1600px] mx-auto space-y-10">
      
      {/* Header Section */}
      <motion.div 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col md:flex-row justify-between items-end gap-6 mb-10"
      >
        <div>
          <h1 className="text-4xl font-black text-white tracking-tight mb-2">Portfolio <span className="luxury-gradient-text">Assets</span></h1>
          <p className="text-white/40 text-lg font-medium max-w-2xl">Executive command center for luxury inventory management and strategic asset deployment.</p>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setIsPasteOpen(true)}
            className="bg-white/5 border border-white/10 text-white px-6 py-3 rounded-2xl font-bold text-sm hover:bg-white/10 transition-all flex items-center gap-3 group"
          >
            <Import size={18} className="text-gold group-hover:scale-110 transition-transform" />
            Import Intelligence
          </button>
          <button 
            onClick={() => {
              setEditingProperty(undefined);
              setIsFormOpen(true);
            }}
            className="bg-gold text-navy px-8 py-3 rounded-2xl font-black text-sm hover:scale-105 active:scale-95 transition-all shadow-xl shadow-gold/20 flex items-center gap-3"
          >
            <Plus size={20} />
            Incorporate Asset
          </button>
        </div>
      </motion.div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Total Assets', value: stats.total, icon: <Package size={20} />, color: 'blue' },
          { label: 'Currently Available', value: stats.available, icon: <CheckCircle2 size={20} />, color: 'emerald' },
          { label: 'Featured Portfolio', value: stats.featured, icon: <Star size={20} />, color: 'gold' },
          { label: 'Stale Intelligence', value: stats.stale, icon: <Clock size={20} />, color: 'orange' },
        ].map((stat, i) => (
          <motion.div 
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.1 }}
            whileHover={{ y: -5, backgroundColor: 'rgba(255,255,255,0.04)' }}
            className="bg-white/[0.02] border border-white/[0.05] p-6 rounded-3xl flex items-center gap-5 transition-all"
          >
            <div className={`w-12 h-12 rounded-2xl bg-${stat.color}-500/10 border border-${stat.color}-500/20 flex items-center justify-center text-${stat.color}-500`}>
              {stat.icon}
            </div>
            <div>
              <div className="text-[10px] font-black text-white/30 uppercase tracking-widest">{stat.label}</div>
              <div className="text-2xl font-black text-white">{stat.value}</div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Filter Bar */}
      <div className="bg-white/[0.02] border border-white/[0.05] p-5 rounded-3xl flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex flex-wrap items-center gap-4 flex-1">
          <div className="relative w-full md:w-[300px] group">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-gold transition-colors" />
            <input 
              value={filters.search}
              onChange={e => setFilters({...filters, search: e.target.value})}
              placeholder="Search assets, codes, or compounds..."
              className="w-full bg-white/[0.03] border border-white/5 rounded-2xl py-3 ps-12 pe-6 text-sm text-white focus:outline-none focus:border-gold/30 transition-all"
            />
          </div>
          <select 
            value={filters.status} 
            onChange={e => setFilters({...filters, status: e.target.value as any})}
            className="bg-white/[0.03] border border-white/5 rounded-2xl px-4 py-3 text-sm text-white/70 focus:outline-none focus:border-gold/30"
          >
            <option value="" className="bg-navy">All Statuses</option>
            <option value="available" className="bg-navy">Available Assets</option>
            <option value="reserved" className="bg-navy">Reserved Units</option>
            <option value="sold" className="bg-navy">Closed Sales</option>
          </select>
          <select 
            value={filters.offer_type} 
            onChange={e => setFilters({...filters, offer_type: e.target.value as any})}
            className="bg-white/[0.03] border border-white/5 rounded-2xl px-4 py-3 text-sm text-white/70 focus:outline-none focus:border-gold/30"
          >
            <option value="" className="bg-navy">All Offers</option>
            <option value="sale" className="bg-navy">Resale/Primary</option>
            <option value="rent" className="bg-navy">Rental Inventory</option>
          </select>
        </div>
        <div className="flex items-center gap-2">
          <button className="p-3 rounded-xl bg-gold text-navy"><List size={18} /></button>
          <button className="p-3 rounded-xl bg-white/5 text-white/30 hover:text-white transition-colors"><LayoutGrid size={18} /></button>
        </div>
      </div>

      {/* Asset Table */}
      <div className="bg-white/[0.02] border border-white/[0.05] rounded-[2rem] overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-white/[0.03] border-bottom border-white/5">
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Asset Code</th>
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Primary Descriptor</th>
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Compound</th>
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Valuation</th>
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Status</th>
              <th className="p-6 text-[11px] font-black text-white/30 uppercase tracking-widest">Freshness</th>
              <th className="p-6 text-right text-[11px] font-black text-white/30 uppercase tracking-widest">Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={7} className="p-20 text-center text-white/20 font-black uppercase tracking-[0.4em]">Incurring intelligence data...</td></tr>
            ) : filteredProperties.length === 0 ? (
              <tr><td colSpan={7} className="p-20 text-center text-white/20 font-black uppercase tracking-[0.4em]">No matching assets found.</td></tr>
            ) : filteredProperties.map((prop, idx) => (
              <motion.tr 
                key={prop.id}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: idx * 0.05 }}
                onClick={() => setSelectedProperty(prop)}
                className="group border-b border-white/[0.02] hover:bg-white/[0.03] cursor-pointer transition-colors"
              >
                <td className="p-6">
                  <div className={`
                    inline-block px-3 py-1 rounded-lg text-[10px] font-mono font-bold border
                    ${prop.is_featured ? 'bg-gold/10 border-gold/30 text-gold shadow-[0_0_10px_rgba(200,169,110,0.1)]' : 'bg-white/5 border-white/10 text-white/60'}
                  `}>
                    {prop.unit_code}
                  </div>
                </td>
                <td className="p-6">
                  <div className="font-bold text-white text-base group-hover:text-gold transition-colors">{prop.title_en}</div>
                  <div className="text-xs text-white/30 font-medium mt-1">{prop.bedrooms} BR • {prop.furnishing}</div>
                </td>
                <td className="p-6">
                  <div className="flex items-center gap-2 text-sm text-white/60">
                    <MapPin size={14} className="text-gold/50" />
                    {prop.compound_name}
                  </div>
                </td>
                <td className="p-6">
                  <div className="font-black text-white text-base">{prop.price.toLocaleString()} <span className="text-[10px] text-white/30">{prop.currency}</span></div>
                  <div className="text-[10px] font-black text-gold/60 uppercase tracking-widest mt-1">{prop.offer_type}</div>
                </td>
                <td className="p-6">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full" style={{ background: getStatusColor(prop.status), boxShadow: `0 0 10px ${getStatusColor(prop.status)}80` }} />
                    <span className="text-[10px] font-black text-white/70 uppercase tracking-widest">{prop.status}</span>
                  </div>
                </td>
                <td className="p-6">
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-bold text-white/40">
                      {prop.freshness_date?.toDate ? prop.freshness_date.toDate().toLocaleDateString() : 'Recent'}
                    </span>
                    {prop.stale_flag && <div className="w-2 h-2 rounded-full bg-orange-500 animate-pulse" />}
                  </div>
                </td>
                <td className="p-6 text-right">
                  <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        setEditingProperty(prop);
                        setIsFormOpen(true);
                      }}
                      className="p-2 rounded-xl bg-white/5 hover:bg-gold hover:text-navy transition-all"
                    >
                      <MoreHorizontal size={18} />
                    </button>
                  </div>
                </td>
              </motion.tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modals & Drawings */}
      <AnimatePresence>
        {isFormOpen && (
          <PropertyForm 
            property={editingProperty}
            onSave={editingProperty ? handleUpdate : handleCreate}
            onClose={() => setIsFormOpen(false)}
          />
        )}
        
        {isPasteOpen && (
          <PasteUnit 
            onSave={handleCreate}
            onClose={() => setIsPasteOpen(false)}
          />
        )}

        {selectedProperty && (
          <PropertyDrawer 
            property={selectedProperty}
            onClose={() => setSelectedProperty(null)}
            onEdit={(p) => {
              setSelectedProperty(null);
              setEditingProperty(p);
              setIsFormOpen(true);
            }}
            onDelete={handleDelete}
          />
        )}
      </AnimatePresence>

      <style>{`
        .luxury-gradient-text {
          background: linear-gradient(135deg, #C8A96E 0%, #F5E6C8 50%, #C8A96E 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }
      `}</style>
    </div>
  );
}

"use client";
import React, { useState, useEffect } from 'react';
import { motion, type Variants } from 'framer-motion';
import { 
  Search, 
  Filter, 
  MoreVertical, 
  Mail, 
  Phone,
  ArrowUpRight,
  ShieldCheck
} from 'lucide-react';

import { db } from '../../lib/firebase';
import { collection, query, onSnapshot, orderBy } from 'firebase/firestore';
import { UserProfile, COLLECTIONS } from '../../lib/models/schema';
import AddAdvisorModal from './AddAdvisorModal';
import { useI18n } from '../../lib/I18nContext';

export default function TeamCRM() {
  const { locale, t } = useI18n();
  const [team, setTeam] = useState<UserProfile[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const q = query(collection(db, COLLECTIONS.users), orderBy('displayName', 'asc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const usersData: UserProfile[] = [];
      snapshot.forEach((doc) => {
        usersData.push({ id: doc.id, ...doc.data() } as UserProfile);
      });
      setTeam(usersData);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const filteredTeam = team.filter(member => 
    member.displayName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    member.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
    member.role.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const containerVariants: Variants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants: Variants = {
    hidden: { y: 30, opacity: 0, scale: 0.95 },
    visible: {
      y: 0,
      opacity: 1,
      scale: 1,
      transition: { duration: 0.8, ease: [0.16, 1, 0.3, 1] as [number, number, number, number] }
    }
  };

  return (
    <div 
      className="p-8 space-y-8 max-w-[1600px] mx-auto min-h-screen"
      onMouseMove={(e) => {
        const rect = e.currentTarget.getBoundingClientRect();
        setMousePos({
          x: (e.clientX - rect.left) / rect.width - 0.5,
          y: (e.clientY - rect.top) / rect.height - 0.5
        });
      }}
    >
      <AddAdvisorModal 
        isOpen={isAddModalOpen} 
        onClose={() => setIsAddModalOpen(false)} 
      />

      {/* ── Header ── */}
      <motion.div 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col md:flex-row md:items-center justify-between gap-6"
      >
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="h-[1px] w-8 bg-gold/50" />
            <span className="text-[10px] font-black text-gold uppercase tracking-[0.4em]">
              {t('admin.humanCapital')}
            </span>
          </div>
          <h1 className="text-4xl font-black text-white tracking-tight leading-tight">
            Team <span className="luxury-gradient-text">CRM</span>
          </h1>
          <p className="text-white/40 mt-1 font-medium max-w-md">
            {t('admin.crmDescription')}
          </p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative group">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30 group-focus-within:text-gold transition-colors" />
            <input 
              type="text" 
              placeholder={t('admin.searchAdvisors')}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-white/[0.03] border border-white/5 rounded-2xl py-3 ps-12 pe-6 text-sm text-white focus:outline-none focus:border-gold/30 focus:bg-white/[0.05] transition-all w-[300px]"
            />
          </div>
          <button className="p-3 rounded-2xl bg-white/[0.03] border border-white/5 text-white/50 hover:text-white transition-colors">
            <Filter size={20} />
          </button>
          <button 
            onClick={() => setIsAddModalOpen(true)}
            className="bg-gold text-navy px-8 py-3 rounded-2xl font-bold text-sm hover:scale-105 transition-transform active:scale-95 shadow-xl shadow-gold/20 flex items-center gap-2"
          >
            {t('admin.addAdvisor')}
          </button>
        </div>
      </motion.div>

      {/* ── Team Grid ── */}
      <motion.div 
        variants={containerVariants}
        initial="hidden"
        animate="visible"
        className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-8"
      >
        {loading ? (
          <div className="col-span-full py-20 text-center flex flex-col items-center gap-4">
            <div className="w-12 h-12 border-2 border-gold/20 border-t-gold rounded-full animate-spin" />
            <span className="text-white/20 font-black uppercase tracking-[0.4em]">{t('admin.initializing')}</span>
          </div>
        ) : filteredTeam.length === 0 ? (
          <div className="col-span-full py-20 text-center text-white/20 font-black uppercase tracking-[0.4em] border border-white/5 rounded-[3rem] bg-white/[0.01]">
            {t('admin.noAdvisors')}
          </div>
        ) : filteredTeam.map((member, idx) => {
          const initials = member.displayName.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();
          return (
            <motion.div
              key={member.id}
              variants={itemVariants}
              whileHover={{ 
                y: -12, 
                rotateX: mousePos.y * 15,
                rotateY: mousePos.x * 15,
                backgroundColor: 'rgba(255,255,255,0.06)',
                borderColor: 'rgba(200,169,110,0.3)',
                transition: { duration: 0.3 }
              }}
              style={{ perspective: 1000 }}
              className="group bg-white/[0.02] border border-white/[0.05] rounded-[2.5rem] p-8 transition-all duration-500 relative overflow-hidden flex flex-col"
            >
              {/* Card Decoration */}
              <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                <ArrowUpRight size={16} className="text-gold" />
              </div>
              
              <div className="flex justify-between items-start mb-8">
                <div className="w-16 h-16 rounded-[1.25rem] bg-gradient-to-br from-gold/20 to-gold/5 border border-gold/20 flex items-center justify-center text-gold text-xl font-black shadow-lg">
                  {initials}
                </div>
                <div className="flex flex-col items-end gap-1">
                   <div className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase tracking-[0.2em] border ${
                     member.status === 'active' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-white/5 border-white/10 text-white/30'
                   }`}>
                     {t(`admin.${member.status}`) || member.status}
                   </div>
                   <button className="p-2 text-white/10 hover:text-white transition-colors">
                     <MoreVertical size={20} />
                   </button>
                </div>
              </div>
  
              <div className="flex-1">
                <h3 className="text-2xl font-black text-white group-hover:text-gold transition-colors tracking-tight">
                  {member.displayName}
                </h3>
                <div className="flex items-center gap-2 mt-1">
                  <ShieldCheck size={12} className="text-gold/60" />
                  <p className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em]">{member.role}</p>
                </div>
              </div>
  
              <div className="mt-8 space-y-4">
                 <div className="flex items-center justify-between p-3 rounded-2xl bg-white/[0.02] border border-white/5">
                   <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-white/30">
                       <Mail size={14} />
                     </div>
                     <span className="text-[11px] font-bold text-white/60 truncate max-w-[120px]">{member.email}</span>
                   </div>
                   <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-white/30">
                       <Phone size={14} />
                     </div>
                   </div>
                 </div>

                 <div className="grid grid-cols-2 gap-3 pt-4 border-t border-white/5">
                    <div className="flex flex-col">
                      <span className="text-[9px] font-black text-white/20 uppercase tracking-widest">{t('admin.performance')}</span>
                      <span className="text-sm font-bold text-white">Top 5%</span>
                    </div>
                    <div className="flex flex-col items-end">
                      <span className="text-[9px] font-black text-white/20 uppercase tracking-widest">{t('admin.portfolio')}</span>
                      <span className="text-sm font-bold text-gold">$12M</span>
                    </div>
                 </div>
              </div>
  
              {/* Quick Actions Hover Surface */}
              <div className="mt-8 flex gap-2 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-y-4 group-hover:translate-y-0">
                <button className="flex-1 bg-white/5 hover:bg-gold hover:text-navy text-white/70 py-3 rounded-xl transition-all font-bold text-[10px] uppercase tracking-widest">
                  {t('admin.connect')}
                </button>
                <button className="flex-1 bg-gold/10 hover:bg-gold/20 text-gold py-3 rounded-xl transition-all font-bold text-[10px] uppercase tracking-widest">
                  {t('admin.intelligence')}
                </button>
              </div>

              {/* Background Glow */}
              <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-gold/5 blur-[60px] rounded-full group-hover:bg-gold/10 transition-all duration-700" />
            </motion.div>
          );
        })}
      </motion.div>

      <style>{`
        .luxury-gradient-text {
          background: linear-gradient(135deg, #C8A96E 0%, #F5E6C8 50%, #C8A96E 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }
      `}</style>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/lib/AuthContext';
import OverviewPage from './pages/OverviewPage';
import AgentsPage from './pages/AgentsPage';
import WorkflowsPage from './pages/WorkflowsPage';
import LeadsPage from './pages/LeadsPage';
import CuratorPage from './pages/CuratorPage';
import ScribePage from './pages/ScribePage';
import ReportsPage from './pages/ReportsPage';
import SettingsPage from './pages/SettingsPage';
import OpenClawPage from './pages/OpenClawPage';
import NexusAIPage from './pages/NexusAIPage';
import DashboardSidebar from './ui/DashboardSidebar';
import DashboardTopbar from './ui/DashboardTopbar';

type PageId =
  | 'overview' | 'agents' | 'workflows' | 'openclaw' | 'nexus'
  | 'leads' | 'listings' | 'curator' | 'scribe' | 'closer'
  | 'reports' | 'settings';

interface NavItem {
  id: PageId;
  label: string;
  icon: string;
  section: string;
  badge?: string;
  badgeColor?: 'red' | 'green' | 'blue';
}

const NAV_ITEMS: NavItem[] = [
  { id: 'overview', label: 'Intelligence OS', icon: '🏠', section: 'Main' },
  { id: 'agents', label: 'Agents & Bots', icon: '🤖', section: 'Main', badge: '6', badgeColor: 'green' },
  { id: 'workflows', label: 'Workflows & Sync', icon: '⚡', section: 'Main', badge: '8', badgeColor: 'blue' },
  { id: 'openclaw', label: 'OpenClaw Terminal', icon: '⚙️', section: 'Main' },
  { id: 'nexus', label: 'Nexus-AI Telemetry', icon: '📡', section: 'Main', badge: 'LIVE', badgeColor: 'green' },
  { id: 'leads', label: 'CRM · Leads', icon: '👥', section: 'Operations', badge: '23', badgeColor: 'red' },
  { id: 'listings', label: 'Listings Hub', icon: '🏘️', section: 'Operations' },
  { id: 'curator', label: 'The Curator', icon: '🎨', section: 'Operations' },
  { id: 'scribe', label: 'The Scribe', icon: '✍️', section: 'Operations' },
  { id: 'closer', label: 'Stage-9 Closer', icon: '💼', section: 'Operations' },
  { id: 'reports', label: 'Reports', icon: '📊', section: 'Analytics' },
  { id: 'settings', label: 'System Config', icon: '🔧', section: 'System' },
];

export default function DashboardContent() {
  const { role, loading } = useAuth();
  const [tab, setTab] = useState<PageId>('overview');
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [lang, setLang] = useState<'en' | 'ar'>('en');

  // Persist theme and language
  useEffect(() => {
    const savedTheme = (localStorage.getItem('dashboard_theme') as 'dark' | 'light') || 'dark';
    const savedLang = (localStorage.getItem('dashboard_lang') as 'en' | 'ar') || 'en';
    setTheme(savedTheme);
    setLang(savedLang);
    document.documentElement.setAttribute('data-theme', savedTheme);
    document.documentElement.setAttribute('dir', savedLang === 'ar' ? 'rtl' : 'ltr');
  }, []);

  const handleThemeChange = useCallback((newTheme: 'dark' | 'light') => {
    setTheme(newTheme);
    localStorage.setItem('dashboard_theme', newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
  }, []);

  const handleLangChange = useCallback((newLang: 'en' | 'ar') => {
    setLang(newLang);
    localStorage.setItem('dashboard_lang', newLang);
    document.documentElement.setAttribute('dir', newLang === 'ar' ? 'rtl' : 'ltr');
  }, []);

  const renderPage = useCallback(() => {
    const pages: Record<PageId, React.ReactNode> = {
      overview: <OverviewPage />,
      agents: <AgentsPage />,
      workflows: <WorkflowsPage />,
      openclaw: <OpenClawPage />,
      nexus: <NexusAIPage />,
      leads: <LeadsPage />,
      listings: <div className="text-center py-16 text-gray-400">Listings Hub · Coming Soon</div>,
      curator: <CuratorPage />,
      scribe: <ScribePage />,
      closer: <div className="text-center py-16 text-gray-400">Stage-9 Closer · Coming Soon</div>,
      reports: <ReportsPage />,
      settings: <SettingsPage />,
    };
    return pages[tab] || pages.overview;
  }, [tab]);

  const getPageTitle = useCallback(() => {
    return NAV_ITEMS.find(n => n.id === tab)?.label || 'Sierra Estates';
  }, [tab]);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="text-center">
          <div className="text-sm font-mono text-[#C9A84C] tracking-widest uppercase animate-pulse">
            Authenticating…
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#07111E]" data-theme={theme} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
      {/* Desktop Sidebar */}
      <DashboardSidebar
        items={NAV_ITEMS}
        activeTab={tab}
        collapsed={collapsed}
        onTabChange={(id) => setTab(id as PageId)}
        onCollapsedChange={setCollapsed}
        className="hidden lg:flex"
      />

      {/* Mobile Sidebar Overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 z-40 lg:hidden">
          <div
            className="absolute inset-0 bg-black/55 backdrop-blur-sm"
            onClick={() => setMobileOpen(false)}
          />
          <DashboardSidebar
            items={NAV_ITEMS}
            activeTab={tab}
            collapsed={false}
            onTabChange={(id) => {
              setTab(id as PageId);
              setMobileOpen(false);
            }}
            onCollapsedChange={() => {}}
            isMobile
            className="absolute left-0 top-0 bottom-0 w-64 z-50"
          />
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Topbar */}
        <DashboardTopbar
          title={getPageTitle()}
          onMenuClick={() => setMobileOpen(true)}
          theme={theme}
          lang={lang}
          onThemeChange={handleThemeChange}
          onLangChange={handleLangChange}
        />

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          {renderPage()}
        </div>
      </div>
    </div>
  );
}

