        ))}
      </div>

      {/* Main Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Pipeline Chart */}
        <div className="lg:col-span-1 bg-[#0F2035] border border-white/8 rounded-xl p-4">
          <div className="text-xs font-bold tracking-widest uppercase text-[#C9A84C] mb-4">
            Pipeline · S1→S10
          </div>
          <PipelineChart />
        </div>

        {/* Hot Leads */}
        <div className="lg:col-span-1 bg-[#0F2035] border border-white/8 rounded-xl overflow-hidden">
          <div className="px-4 py-3 border-b border-white/5">
            <div className="text-xs font-bold tracking-widest uppercase text-[#C9A84C]">
              🔥 Hot Leads
            </div>
            <span className="text-xs px-2 py-1 rounded-full bg-[#E63946]/20 text-[#E63946] font-bold inline-block mt-2">
              3 urgent
            </span>
          </div>
          <LeadsList leads={leads.filter(l => l.hot)} />
        </div>

        {/* Agent Status */}
        <div className="lg:col-span-1 bg-[#0F2035] border border-white/8 rounded-xl overflow-hidden">
          <div className="px-4 py-3 border-b border-white/5">
            <div className="text-xs font-bold tracking-widest uppercase text-[#C9A84C]">
              Agent Status
            </div>
          </div>
          <div className="p-4">
            <AgentStatusList />
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { Shield } from 'lucide-react';
import { useAuth } from '@/lib/AuthContext';

interface NavItem {
  id: string;
  label: string;
  icon: string;
  section: string;
  badge?: string;
  badgeColor?: 'red' | 'green' | 'blue';
}

const BADGE_COLORS = {
  red: 'bg-[#E63946] text-white',
  green: 'bg-[#34D399] text-[#071422]',
  blue: 'bg-[#1E88D9] text-white',
};

const SECTION_ORDER = ['Main', 'Operations', 'Analytics', 'System'];

interface DashboardSidebarProps {
  items: NavItem[];
  activeTab: string;
  collapsed: boolean;
  onTabChange: (id: NavItem['id']) => void;
  onCollapsedChange: (collapsed: boolean) => void;
  isMobile?: boolean;
  className?: string;
}

export default function DashboardSidebar({
  items,
  activeTab,
  collapsed,
  onTabChange,
  onCollapsedChange,
  isMobile = false,
  className = '',
}: DashboardSidebarProps) {
  const { role, signOut } = useAuth();

  const sections = SECTION_ORDER.filter(sec => items.some(item => item.section === sec));
  const visibleItems = items.filter(item =>
    item.section === 'Main' ||
    item.section === 'Operations' ||
    (role === 'admin' || role === 'manager') && item.section === 'Analytics' ||
    role === 'admin' && item.section === 'System'
  );

  return (
    <aside
      className={`flex flex-col w-[220px] ${collapsed ? 'lg:w-[56px]' : ''} shrink-0 bg-[#0B1A2E] border-r border-white/5 transition-all duration-300 ${className}`}
    >
      {/* Logo */}
      <div className="flex items-center gap-3 px-4 lg:px-8 py-6 lg:py-8 border-b border-white/5 min-h-[64px]">
        <Shield size={28} className="text-[#C9A84C]" />
        {!collapsed && (
          <div className="overflow-hidden">
            <div className="text-white font-bold text-sm uppercase tracking-tight">
              Sierra Estates
            </div>
            <div className="text-white/30 text-[9px] tracking-widest uppercase font-mono">
              Intelligence OS
            </div>
          </div>
        )}
      </div>

      {/* Nav Sections */}
      <nav className="flex-1 px-3 lg:px-4 py-4 space-y-0.5 overflow-y-auto">
        {sections.map(section => (
          <div key={section}>
            {!collapsed && (
              <div className="px-3 lg:px-4 pt-2 pb-1 text-[8px] font-bold tracking-widest uppercase text-white/25 font-mono">
                {section}
              </div>
            )}
            {visibleItems
              .filter(item => item.section === section)
              .map(item => (
                <button
                  key={item.id}
                  onClick={() => onTabChange(item.id)}
                  className={`w-full flex items-center gap-3 px-3 lg:px-4 py-3 rounded-lg text-sm font-medium transition-all border-l-2 pl-[12px] lg:pl-[14px] ${
                    activeTab === item.id
                      ? 'bg-white/6 text-[#C9A84C] border-[#C9A84C]'
                      : 'text-white/55 hover:text-white/90 hover:bg-white/4 border-transparent'
                  }`}
                  title={collapsed ? item.label : ''}
                >
                  <span className="flex-shrink-0 text-base">{item.icon}</span>
                  {!collapsed && (
                    <>
                      <span className="flex-1">{item.label}</span>
                      {item.badge && (
                        <span className={`text-[8px] font-bold px-1.5 py-0.5 rounded-full ${BADGE_COLORS[item.badgeColor ?? 'blue']}`}>
                          {item.badge}
                        </span>
                      )}
                    </>
                  )}
                </button>
              ))}
          </div>
        ))}
      </nav>

      {/* Role Pill + Sign Out */}
      {!isMobile && (
        <div className="px-3 lg:px-4 pb-6 border-t border-white/5 pt-4">
          {role && !collapsed && (
            <div className="px-3 lg:px-4 pb-3 text-[9px] text-white/30 tracking-widest uppercase font-mono">
              Signed in · <span className="text-[#C9A84C]">{role}</span>
            </div>
          )}
          <button
            onClick={() => signOut()}
            className="w-full flex items-center gap-3 px-3 lg:px-4 py-3 text-white/40 hover:text-white/80 text-sm transition-colors rounded-lg hover:bg-white/4"
          >
            <span className="flex-shrink-0 text-lg">🚪</span>
            {!collapsed && <span>Sign Out</span>}
          </button>
        </div>
      )}
    </aside>
  );
}

"use client";
import React, { useState, useEffect } from 'react';
import { db } from '@/lib/firebase';
import { 
  collection, 
  query, 
  onSnapshot, 
  orderBy 
} from 'firebase/firestore';
import { useI18n } from '@/lib/I18nContext';

interface Stakeholder {
  id: string;
  name: string;
  phone: string;
  portfolioPreference: string;
  capitalAllocation: string;
  strategicIntensity: string;
  phase: string;
  createdAt: any;
  assignedPartnerName?: string;
  originChannel: string;
}

export default function ClientsScreen() {
  const { t, locale } = useI18n();
  const [stakeholders, setStakeholders] = useState<Stakeholder[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [filterPhase, setFilterPhase] = useState('all');

  useEffect(() => {
    const q = query(collection(db, 'leads'), orderBy('createdAt', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Stakeholder[];
      setStakeholders(data);
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const filtered = stakeholders.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(search.toLowerCase()) || 
                         s.phone.includes(search) ||
                         s.portfolioPreference.toLowerCase().includes(search.toLowerCase());
    const matchesPhase = filterPhase === 'all' || s.phase === filterPhase;
    return matchesSearch && matchesPhase;
  });

  if (loading) {
    return (
      <div className="section-loader">
        <div className="loader-logo sm">SB</div>
        <p className="mt-4 text-xs tracking-widest opacity-50 uppercase">Assembling Portfolio Intelligence...</p>
      </div>
    );
  }

  return (
    <div className="clients-screen animate-fade-in-up">
      <div className="page-header" style={{ marginBottom: '40px' }}>
        <h1 className="serif text-3xl mb-2 gold-underline">{locale === 'ar' ? 'محفظة المستثمرين' : 'Global Stakeholder Portfolio'}</h1>
        <p className="text-secondary text-sm">Comprehensive record of all active prospects, historical interactions, and asset allocations</p>
      </div>

      <div className="action-bar-luxury glass-panel mb-8 p-4 flex items-center justify-between gap-4">
        <div className="flex-1 relative">
          <span className="absolute start-4 top-1/2 -translate-y-1/2 opacity-30">🔍</span>
          <input 
            type="text" 
            className="w-full ps-12 pe-4 py-3 bg-white/5 border border-white/10 rounded-xl focus:border-gold/50 outline-none transition-all text-sm"
            placeholder={locale === 'ar' ? 'ابحث بالاسم أو الهاتف أو المشروع...' : 'Search by name, phone, or portfolio preference...'}
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
        
        <select 
          className="bg-navy-dark border border-white/10 rounded-xl px-4 py-3 text-sm outline-none focus:border-gold/50"
          value={filterPhase}
          onChange={e => setFilterPhase(e.target.value)}
        >
          <option value="all">{locale === 'ar' ? 'جميع المراحل' : 'All Phases'}</option>
          <option value="acquisition">{locale === 'ar' ? 'استحواذ' : 'Acquisition'}</option>
          <option value="consultation">{locale === 'ar' ? 'استشارة' : 'Consultation'}</option>
          <option value="inspection">{locale === 'ar' ? 'معاينة' : 'Inspection'}</option>
          <option value="structuring">{locale === 'ar' ? 'هيكلة الصفقة' : 'Structuring'}</option>
          <option value="settlement">{locale === 'ar' ? 'تمت الصفقة' : 'Settled'}</option>
        </select>

        <button className="btn btn-outline btn-sm py-3 px-6 h-auto">
          {locale === 'ar' ? 'تصدير التقرير' : 'Export Ledger'}
        </button>
      </div>

      <div className="table-luxury-wrapper overflow-hidden rounded-2xl border border-white/5 shadow-2xl">
        <table className="w-full text-left border-collapse bg-white/[0.02] backdrop-blur-md">
          <thead>
            <tr className="bg-white/5 uppercase text-[10px] tracking-widest font-bold text-gold/80">
              <th className="px-6 py-5">{locale === 'ar' ? 'المستثمر' : 'Stakeholder Identity'}</th>
              <th className="px-6 py-5">{locale === 'ar' ? 'التخصيص المالي' : 'Capital Allocation'}</th>
              <th className="px-6 py-5">{locale === 'ar' ? 'الأصول المفضلة' : 'Portfolio Focus'}</th>
              <th className="px-6 py-5">{locale === 'ar' ? 'المستشار المسؤول' : 'Assigned Advisor'}</th>
              <th className="px-6 py-5">{locale === 'ar' ? 'المرحلة الحالية' : 'Operational Phase'}</th>
              <th className="px-6 py-5">{locale === 'ar' ? 'تاريخ الدخول' : 'Ingestion Date'}</th>
            </tr>
          </thead>
          <tbody className="text-sm">
            {filtered.map((s, idx) => (
              <tr key={s.id} className="border-t border-white/5 hover:bg-white/[0.03] transition-colors group cursor-pointer">
                <td className="px-6 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-gradient-to-br from-gold/40 to-gold/10 flex items-center justify-center text-[10px] font-bold text-gold">
                      {s.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase()}
                    </div>
                    <div>
                      <div className="font-bold text-white group-hover:text-gold transition-colors">{s.name}</div>
                      <div className="text-[10px] opacity-40">{s.phone}</div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-5 font-mono text-gold/90">{s.capitalAllocation}</td>
                <td className="px-6 py-5">{s.portfolioPreference}</td>
                <td className="px-6 py-5 opacity-70 italic">{s.assignedPartnerName || 'Unassigned'}</td>
                <td className="px-6 py-5">
                  <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${
                    s.phase === 'settlement' ? 'bg-emerald-500/10 text-emerald-500' :
                    s.phase === 'acquisition' ? 'bg-blue-500/10 text-blue-500' : 'bg-gold/10 text-gold'
                  }`}>
                    {s.phase}
                  </span>
                </td>
                <td className="px-6 py-5 opacity-40 text-xs">
                  {s.createdAt?.toDate ? s.createdAt.toDate().toLocaleDateString() : 'Historical'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filtered.length === 0 && (
          <div className="py-20 text-center opacity-30 italic">No stakeholders matching your search criteria were found in the ledger.</div>
        )}
      </div>

      <style>{`
        .gold-underline {
          position: relative;
          display: inline-block;
        }
        .gold-underline::after {
          content: '';
          position: absolute;
          bottom: -4px;
          left: 0;
          width: 40px;
          height: 2px;
          background: var(--gold);
        }
      `}</style>
    </div>
  );
}

"use client";
import React, { useState, useEffect, useMemo } from 'react';
import { db } from '@/lib/firebase';
import { 
  collection, 
  doc, 
  onSnapshot, 
  updateDoc, 
  addDoc, 
  query,
  orderBy,
  serverTimestamp
} from 'firebase/firestore';
import { useAuth } from '@/lib/AuthContext';
import { useI18n } from '@/lib/I18nContext';
import { 
  Zap, 
  ClipboardCheck, 
  Eye, 
  CheckCircle, 
  MessageSquare, 
  Phone,
  Plus,
  RefreshCw,
  ListTodo,
  X,
  User
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import KPIProgressBar from '../UI/KPIProgressBar';

export default function LeadsFlow() {
  const { user } = useAuth();
  const { t, locale, dir } = useI18n();
  const [leads, setLeads] = useState<any[]>([]);
  const [activeLead, setActiveLead] = useState<any>(null);
  const [isAddingLead, setIsAddingLead] = useState(false);
  const [newLead, setNewLead] = useState({ name: '', phone: '' });
  const [loading, setLoading] = useState(true);

  const workflowSteps = useMemo(() => [
    { id: 'intake', label: t('flow.stages.intake'), icon: <MessageSquare size={16}/> },
    { id: 'ai-discovery', label: t('flow.stages.ai-discovery'), icon: <Zap size={16}/> },
    { id: 'advisory', label: t('flow.stages.advisory'), icon: <ClipboardCheck size={16}/> },
    { id: 'presentation', label: t('flow.stages.presentation'), icon: <Eye size={16}/> },
    { id: 'closed', label: t('flow.stages.closed'), icon: <CheckCircle size={16}/> },
  ], [t]);

  // --- DATA SYNC ---
  useEffect(() => {
    if (!user) return;
    const leadsRef = collection(db, 'leads');
    const q = query(leadsRef, orderBy('updatedAt', 'desc'));
    
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const leadsData = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setLeads(leadsData);
      setLoading(false);
    }, (error) => {
      console.error("Leads sync error:", error);
      setLoading(false);
    });
    
    return () => unsubscribe();
  }, [user]);

  // --- ACTIONS ---
  const updateLeadStatus = async (leadId: string, newStatus: string) => {
    if (!user) return;
    const leadDoc = doc(db, 'leads', leadId);
    try {
      await updateDoc(leadDoc, { 
        status: newStatus, 
        updatedAt: serverTimestamp() 
      });
      if (activeLead && activeLead.id === leadId) {
        setActiveLead({ ...activeLead, status: newStatus });
      }
    } catch (err) { console.error(err); }
  };

  const handleAddLead = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !newLead.name || !newLead.phone) return;
    try {
      const leadsRef = collection(db, 'leads');
      await addDoc(leadsRef, {
        name: newLead.name,
        phone: newLead.phone,
        status: 'intake',
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
        createdBy: user.uid,
        assignedTo: user.uid,
        phase: 'acquisition' // Compatible with ClientsScreen
      });
      setNewLead({ name: '', phone: '' });
      setIsAddingLead(false);
    } catch (err) { console.error(err); }
  };

  const getStatusStyle = (status: string) => {
    const styles: Record<string, string> = {
      'intake': 'badge-blue',
      'ai-discovery': 'badge-navy',
      'advisory': 'badge-gold',
      'presentation': 'badge-warning',
      'closed': 'badge-success'
    };
    return styles[status] || 'badge-navy';
  };

  if (loading) return (
    <div className="section-loader">
      <RefreshCw className="w-10 h-10 text-gold animate-spin mb-4" />
      <div className="loader-text">{t('common.loading')}</div>
    </div>
  );

  return (
    <div className="leads-flow-container animate-fade-in-up" dir={dir}>
      {/* Header Area */}
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '32px' }}>
        <div>
          <h1 className="serif gold-underline" style={{ fontSize: '32px' }}>{t('flow.title')}</h1>
          <div className="page-sub" style={{ opacity: 0.7 }}>{t('flow.subtitle')}</div>
        </div>
        <button className="btn btn-gold shadow-gold" onClick={() => setIsAddingLead(true)}>
          <Plus size={18} className="me-2"/> {t('flow.addLead')}
        </button>
      </div>

      <div className="flow-layout">
        {/* Pipeline Column */}
        <div className="pipeline-sidebar">
          <div className="kpi-section" style={{ marginBottom: '24px' }}>
            <KPIProgressBar 
              label={t('flow.callsTarget') || 'Strategic Calls'} 
              current={8} 
              target={25} 
              color="var(--gold)"
              icon={<Phone size={12} />}
            />
            <KPIProgressBar 
              label={t('flow.messagesTarget') || 'Nexus Messages'} 
              current={34} 
              target={50} 
              color="var(--blue-light)"
              icon={<MessageSquare size={12} />}
            />
          </div>

          <h2 className="sidebar-section-title">{t('flow.listTitle')}</h2>
          <div className="leads-list">
            {leads.length === 0 ? (
              <div className="p-8 text-center opacity-30 italic text-sm">{t('flow.noProspects')}</div>
            ) : (
              leads.map(lead => (
                <motion.div 
                  layoutId={lead.id}
                  key={lead.id} 
                  onClick={() => setActiveLead(lead)}
                  className={`lead-card-luxury glass-panel ${activeLead?.id === lead.id ? 'active' : ''}`}
                >
                  <div className="lead-card-header">
                    <div className="lead-avatar">
                      {lead.name?.[0] || 'U'}
                    </div>
                    <div className="lead-info">
                      <div className="lead-name">{lead.name || 'Unknown'}</div>
                      <div className="lead-phone"><Phone size={12}/> {lead.phone}</div>
                    </div>
                    <div className={`badge ${getStatusStyle(lead.status)}`} style={{ fontSize: '9px', marginLeft: 'auto' }}>
                      {t(`flow.stages.${lead.status}`)}
                    </div>
                  </div>
                </motion.div>
              ))
            )}
          </div>
        </div>

        {/* Engine Column */}
        <div className="engine-content">
          <AnimatePresence mode="wait">
            {activeLead ? (
              <motion.div 
                key={activeLead.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="engine-card glass-panel"
              >
                <div className="engine-card-header">
                  <div className="flex items-center gap-4">
                    <div className="engine-icon-wrap">
                      <RefreshCw size={20} className="text-gold" />
                    </div>
                    <div>
                      <h2 className="serif text-2xl text-gold">{t('flow.engine')}</h2>
                      <p className="text-secondary text-sm uppercase tracking-widest">{activeLead.name}</p>
                    </div>
                  </div>
                  <button onClick={() => setActiveLead(null)} className="btn-ghost p-2 rounded-full"><X size={20}/></button>
                </div>

                {/* Stepper */}
                <div className="stepper-horizontal">
                  {workflowSteps.map((step, idx) => {
                    const isActive = step.id === activeLead.status;
                    const isPast = workflowSteps.findIndex(s => s.id === activeLead.status) > idx;
                    return (
                      <div key={step.id} className="step-item">
                        <button 
                          onClick={() => updateLeadStatus(activeLead.id, step.id)}
                          className={`step-bubble ${isActive ? 'active' : isPast ? 'completed' : ''}`}
                        >
                          {isPast ? <CheckCircle size={18}/> : step.icon}
                        </button>
                        <span className={`step-label ${isActive ? 'active' : ''}`}>{step.label}</span>
                        {idx < workflowSteps.length - 1 && <div className="step-line" />}
                      </div>
                    );
                  })}
                </div>

                {/* Script Section */}
                <div className="script-container">
                  <div className="script-box cinematic-glow">
                    <div className="script-header">
                      <MessageSquare size={14} className="text-gold"/>
                      <span>{t(`flow.scripts.${activeLead.status}.title`)}</span>
                    </div>
                    <div className="script-text">
                      {t(`flow.scripts.${activeLead.status}.text`).replace('{name}', activeLead.name)}
                    </div>
                  </div>

                  {/* Tasks */}
                  <div className="tasks-box">
                    <div className="tasks-header">
                      <ListTodo size={14} className="text-blue-light"/>
                      <span>{t('flow.engine')} Tasks</span>
                    </div>
                    <div className="tasks-grid">
                      {(t(`flow.scripts.${activeLead.status}.tasks`) as unknown as string[]).map((task, i) => (
                        <div key={i} className="task-item">
                          <div className="task-number">{i+1}</div>
                          <div className="task-label">{task}</div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <a href={`tel:${activeLead.phone}`} className="btn btn-primary w-full py-4 justify-center text-lg mt-4" style={{ borderRadius: '16px' }}>
                    <Phone size={20} className="me-3"/> {t('flow.callProspect')}
                  </a>
                </div>
              </motion.div>
            ) : (
              <div className="engine-empty glass-panel">
                <div className="empty-icon">
                  <User size={48} className="text-gold opacity-10" />
                </div>
                <h3 className="serif text-xl opacity-40">{t('flow.stats')}</h3>
                <p className="opacity-20 text-sm max-w-xs">{t('flow.noProspects')}</p>
              </div>
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* Add Lead Modal */}
      {isAddingLead && (
        <div className="modal-overlay reveal">
          <div className="modal-content glass-panel" style={{ maxWidth: '480px', padding: '40px' }}>
            <h2 className="serif text-3xl text-gold mb-8">{t('flow.newProspect')}</h2>
            <form onSubmit={handleAddLead} className="space-y-6">
              <div className="form-group">
                <label className="form-label">{t('crm.leadName')}</label>
                <input 
                  autoFocus required type="text" 
                  value={newLead.name} 
                  onChange={(e) => setNewLead({...newLead, name: e.target.value})} 
                  className="form-input" 
                  placeholder="e.g. John Doe"
                />
              </div>
              <div className="form-group">
                <label className="form-label">{t('crm.phone')}</label>
                <input 
                  required type="tel" 
                  value={newLead.phone} 
                  onChange={(e) => setNewLead({...newLead, phone: e.target.value})} 
                  className="form-input" 
                  dir="ltr"
                  placeholder="01xxxxxxxxx"
