"use client";
import React, { useState, useEffect } from 'react';
import { db } from '@/lib/firebase';
import { collection, query, orderBy, limit, onSnapshot, Timestamp } from 'firebase/firestore';
import { motion, AnimatePresence } from 'framer-motion';
import { RefreshCcw, Bell, Clock, ArrowUpRight, CheckCircle2, Info, Activity } from 'lucide-react';

interface ActivityItem {
  id: string;
  text: string;
  createdAt?: Timestamp;
  color?: string;
  type?: 'sale' | 'listing' | 'lead' | 'system';
}

const getActivityIcon = (text: string, color: string) => {
  const lowerText = text.toLowerCase();
  if (lowerText.includes('sale') || lowerText.includes('transaction')) return <ArrowUpRight size={14} />;
  if (lowerText.includes('listing') || lowerText.includes('unit')) return <CheckCircle2 size={14} />;
  if (lowerText.includes('lead') || lowerText.includes('client')) return <Bell size={14} />;
  return <Info size={14} />;
};

const renderActivityText = (text: string) => {
  const segments = text.split(/(\*\*.*?\*\*)/g).filter(Boolean);

  return segments.map((segment, index) => {
    if (segment.startsWith('**') && segment.endsWith('**')) {
      return <strong key={index} style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{segment.slice(2, -2)}</strong>;
    }
    return <span key={index} style={{ color: 'var(--text-secondary)', opacity: 0.8 }}>{segment}</span>;
  });
};

export default function ActivityList() {
  const [activities, setActivities] = useState<ActivityItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [now, setNow] = useState(() => Date.now());

  useEffect(() => {
    const q = query(collection(db, 'activities'), orderBy('createdAt', 'desc'), limit(12));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const list = snapshot.docs.map((activityDoc) => ({
        id: activityDoc.id,
        ...activityDoc.data()
      } as ActivityItem));
      setActivities(list);
      setLoading(false);
    }, (error) => {
      console.error('Failed to load activity feed:', error);
      setActivities([]);
      setLoading(false);
    });

    const timer = window.setInterval(() => setNow(Date.now()), 30000);
    return () => {
      unsubscribe();
      window.clearInterval(timer);
    };
  }, []);

  const formatTime = (ts: Timestamp | undefined) => {
    if (!ts) return 'Just now';
    const date = ts.toDate();
    const diff = now - date.getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins}m ago`;
    const hours = Math.floor(mins / 60);
    if (hours < 24) return `${hours}h ago`;
    return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  return (
    <div className="cinematic-surface" style={{ 
      borderRadius: '20px', 
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
      height: '100%',
      minHeight: '400px'
    }}>
      <div style={{ 
        padding: '24px 32px', 
        borderBottom: '1px solid rgba(255,255,255,0.05)',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        background: 'rgba(255,255,255,0.01)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{ 
            width: '32px', height: '32px', borderRadius: '8px', 
            background: 'var(--gold)10', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--gold)' 
          }}>
            <Activity size={18} />
          </div>
          <span className="serif" style={{ fontSize: '18px', fontWeight: 600, color: 'var(--text-primary)' }}>
            Operational Velocity
          </span>
        </div>
        {loading ? (
          <RefreshCcw size={14} className="pulse" style={{ color: 'var(--gold)', opacity: 0.5 }} />
        ) : (
          <div style={{ fontSize: '11px', fontWeight: 600, color: 'var(--gold)', background: 'var(--gold)15', padding: '4px 10px', borderRadius: '20px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            Live Feed
          </div>
        )}
      </div>

      <div style={{ padding: '24px 32px', overflowY: 'auto', flex: 1 }}>
        <div style={{ position: 'relative' }}>
          {/* Vertical timeline line */}
          <div style={{ 
            position: 'absolute', 
            left: '11px', 
            top: '8px', 
            bottom: '8px', 
            width: '1px', 
            background: 'linear-gradient(to bottom, transparent, rgba(255,255,255,0.1) 10%, rgba(255,255,255,0.1) 90%, transparent)',
            zIndex: 0
          }}></div>

          <AnimatePresence mode="popLayout">
            {!loading && activities.length === 0 && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                style={{ padding: '40px 0', textAlign: 'center', color: 'var(--text-secondary)', fontSize: '14px', opacity: 0.5 }}
              >
                Zero operational signals detected in the current window.
              </motion.div>
            )}
            
            {activities.map((act, i) => (
              <motion.div 
                key={act.id}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.4, delay: i * 0.05 }}
                style={{ 
                  display: 'flex', 
                  gap: '20px', 
                  marginBottom: '24px', 
                  position: 'relative',
                  zIndex: 2
                }}
              >
                <div style={{ 
                  width: '24px', 
                  height: '24px', 
                  borderRadius: '50%', 
                  background: 'var(--navy-light)',
                  border: `2px solid ${act.color || 'var(--gold)'}`,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: act.color || 'var(--gold)',
                  boxShadow: `0 0 10px ${act.color || 'var(--gold)'}20`,
                  flexShrink: 0,
                  marginTop: '2px'
                }}>
                  {getActivityIcon(act.text, act.color || 'var(--gold)')}
                </div>
                
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: '14.5px', lineHeight: '1.5', color: 'var(--text-primary)' }}>
                    {renderActivityText(act.text)}
                  </div>
                  <div style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '6px', 
                    marginTop: '6px', 
                    fontSize: '12px', 
                    color: 'var(--text-secondary)',
                    opacity: 0.6 
                  }}>
                    <Clock size={12} />
                    {formatTime(act.createdAt)}
                  </div>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
}

"use client";
import React, { useState, useEffect } from 'react';
import { db } from '@/lib/firebase';
import { 
  collection, 
  query, 
  onSnapshot, 
  addDoc, 
  deleteDoc,
  doc, 
  serverTimestamp, 
  orderBy 
} from 'firebase/firestore';
import AdvisorProfile from './AdvisorProfile';
import { useI18n } from '@/lib/I18nContext';

interface Partner {
  id: string;
  name: string;
  role: string;
  deals: number;
  revenue: string;
  initials: string;
  color: string;
  badge?: string;
}

export default function TeamScreen({ onNavigate }: { onNavigate?: (screen: any) => void }) {
  const { locale, t } = useI18n();
  const [partners, setPartners] = useState<Partner[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [selectedAdvisor, setSelectedAdvisor] = useState<Partner | null>(null);
  const [partnerDraft, setPartnerDraft] = useState({
    name: '',
    role: '',
    deals: 0,
    revenue: '',
    initials: '',
    color: 'var(--blue)'
  });

  useEffect(() => {
    const q = query(collection(db, 'partners'), orderBy('name', 'asc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Partner[];
      setPartners(data);
      setLoading(false);
    }, (err) => {
      console.error("Partners sync failed:", err);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const enlistPartner = async () => {
    if (!partnerDraft.name || !partnerDraft.role) return;
    try {
      const initials = partnerDraft.name
        .split(' ')
        .map(n => n[0])
        .join('')
        .toUpperCase()
        .slice(0, 2);

      await addDoc(collection(db, 'partners'), {
        ...partnerDraft,
        initials,
        createdAt: serverTimestamp()
      });
      setShowModal(false);
      setPartnerDraft({ name: '', role: '', deals: 0, revenue: '', initials: '', color: 'var(--blue)' });
    } catch (err) {
      console.error("Enlistment failed:", err);
    }
  };

  const terminatePartner = async (id: string) => {
    if (!confirm("Are you sure you want to terminate this partnership?")) return;
    try {
      await deleteDoc(doc(db, 'partners', id));
    } catch (err) {
      console.error("Termination failed:", err);
    }
  };

  if (loading) {
    return (
      <div className="section-loader">
        <div className="loader-logo sm">SB</div>
        <div className="loader-text sm">Synchronizing Executive Assets…</div>
      </div>
    );
  }

  if (selectedAdvisor) {
    return <AdvisorProfile advisor={selectedAdvisor} onBack={() => setSelectedAdvisor(null)} />;
  }

  return (
    <div className="team-screen animate-fade-in-up stagger-1">
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
        <div>
          <h1 className="serif gold-underline" style={{ fontSize: '28px' }}>{t('team.title')}</h1>
          <div className="page-sub">{t('team.subtitle')}</div>
        </div>
        <button className="btn btn-primary btn-sm" onClick={() => setShowModal(true)}>+ {t('team.enlistPartner')}</button>
      </div>

      <div className="kpi-grid mb-8 mt-2">
        <div className="kpi-card cinematic-glow">
          <div className="kpi-label">{t('team.strategicPersonnel')}</div>
          <div className="kpi-value">{partners.length}</div>
          <div className="kpi-badge blue">ADVISORS</div>
        </div>
        <div className="kpi-card cinematic-glow">
          <div className="kpi-label">{t('team.yieldBenchmarking')}</div>
          <div className="kpi-value gold">2.4%</div>
          <div className="kpi-badge up">+0.2%</div>
        </div>
        <div className="kpi-card cinematic-glow">
          <div className="kpi-label">{t('team.objectiveFulfillment')}</div>
          <div className="kpi-value">92%</div>
          <div className="kpi-badge blue">STABLE</div>
        </div>
        <div className="kpi-card cinematic-glow">
          <div className="kpi-label">{t('team.avgPayout')}</div>
          <div className="kpi-value gold">EGP 124K</div>
          <div className="kpi-badge warn">NET</div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
        {partners.map((agent, index) => (
          <div className={`card glass-panel hover:border-gold/30 transition-all duration-500 animate-fade-in-up stagger-${(index % 4) + 1}`} key={agent.id} style={{ padding: '24px', position: 'relative' }}>
            <button 
              onClick={() => terminatePartner(agent.id)}
              style={{ position: 'absolute', top: '15px', right: '15px', background: 'none', border: 'none', opacity: 0.15, cursor: 'pointer', fontSize: '12px' }}
              className="hover:opacity-100 transition-opacity"
            >
              ✕
            </button>
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
              <div className="user-avatar" style={{ margin: 0, width: '56px', height: '56px', fontSize: '20px', background: agent.color, boxShadow: `0 0 15px ${agent.color}33` }}>
                {agent.initials}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: '18px', color: 'var(--text-primary)' }}>{agent.name}</div>
                <div style={{ fontSize: '11px', opacity: 0.5, letterSpacing: '1px', textTransform: 'uppercase', fontWeight: 600 }}>{agent.role}</div>
              </div>
              {agent.deals > 10 && (
                <div style={{ textAlign: 'right' }}>
                  <div className="badge badge-gold" style={{ fontSize: '9px', padding: '2px 8px' }}>Elite</div>
                </div>
              )}
            </div>
            
            <div style={{ marginTop: '24px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', padding: '15px', background: 'rgba(255,255,255,0.03)', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div>
                <div style={{ fontSize: '10px', opacity: 0.4, textTransform: 'uppercase', fontWeight: 700, letterSpacing: '0.5px' }}>Liquidation</div>
                <div style={{ fontWeight: 700, color: 'var(--gold)', fontSize: '15px' }}>{agent.revenue} EGP</div>
              </div>
              <div>
                <div style={{ fontSize: '10px', opacity: 0.4, textTransform: 'uppercase', fontWeight: 700, letterSpacing: '0.5px' }}>Volume</div>
                <div style={{ fontWeight: 700, fontSize: '15px' }}>{agent.deals} Assets</div>
              </div>
            </div>

            <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
              <button className="btn btn-outline btn-sm" style={{ flex: 1 }} onClick={() => setSelectedAdvisor(agent)}>Profile</button>
              <button className="btn btn-ghost btn-sm" style={{ flex: 1 }}>Message</button>
            </div>
          </div>
        ))}

        <div className="card hover:border-gold/50 hover:bg-gold/5 transition-all duration-300" onClick={() => setShowModal(true)} style={{ 
          padding: '24px', 
          display: 'flex', 
          flexDirection: 'column',
          alignItems: 'center', 
          justifyContent: 'center', 
          border: '2px dashed rgba(200,169,110,0.2)', 
          background: 'rgba(200,169,110,0.02)', 
          cursor: 'pointer',
          minHeight: '234px',
          borderRadius: '20px'
