          <span className="text-sb-gold font-bold text-lg">{property.price.split(' ')[1]}M</span>
        </div>
        
        <div className="flex items-center gap-2 text-white/40 mb-4">
          <MapPin size={14} className="text-sb-gold/60" />
          <span className="text-xs uppercase tracking-widest font-light">{property.location}</span>
        </div>

        <div className="flex items-center gap-6 pt-4 border-t border-white/5">
          <div className="flex items-center gap-2">
            <Bed size={14} className="text-white/30" />
            <span className="text-xs text-white/60 font-light">{property.beds} Beds</span>
          </div>
          <div className="flex items-center gap-2">
            <Bath size={14} className="text-white/30" />
            <span className="text-xs text-white/60 font-light">{property.baths} Baths</span>
          </div>
          <div className="flex items-center gap-2">
            <Maximize size={14} className="text-white/30" />
            <span className="text-xs text-white/60 font-light">{property.sqft} sqft</span>
          </div>
        </div>
      </div>
    </motion.div>
  );
}

'use client';

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Sparkles, Send, User } from 'lucide-react';
import { useSierra } from '@/lib/hooks/useSierra';
import BrandLogo from '@/components/UI/BrandLogo';

/**
 * LEILA CONCIERGE — QUIET LUXURY V12.0
 * The master AI concierge interface for premium lead generation.
 */
export default function SierraConcierge() {
  const [isOpen, setIsOpen] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const { messages, isTyping, handleResponse, stage } = useSierra();
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isTyping]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    handleResponse(inputValue);
    setInputValue('');
  };

  return (
    <div className="fixed bottom-8 right-8 z-[100] font-sans">
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95, filter: 'blur(10px)' }}
            animate={{ opacity: 1, y: 0, scale: 1, filter: 'blur(0px)' }}
            exit={{ opacity: 0, y: 20, scale: 0.95, filter: 'blur(10px)' }}
            className="absolute bottom-20 right-0 w-[400px] h-[600px] bg-[#030712]/95 backdrop-blur-3xl border border-[#C9A24D]/20 rounded-3xl shadow-2xl overflow-hidden flex flex-col"
          >
            {/* Header */}
            <div className="p-6 border-b border-[#C9A24D]/10 flex items-center justify-between bg-black/20">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full border border-[#C9A24D]/30 flex items-center justify-center bg-[#C9A24D]/5 relative">
                  <BrandLogo variant="emblem" size="sm" themeOverride="dark" />
                  <div className="absolute -top-1 -right-1 w-3 h-3 bg-green-500 border-2 border-[#030712] rounded-full" />
                </div>
                <div>
                  <h3 className="text-sm font-serif tracking-[0.2em] uppercase text-[#F4F0E8]">Sierra</h3>
                  <p className="text-[10px] text-[#C9A24D]/60 uppercase tracking-widest font-medium">Master AI Concierge</p>
                </div>
              </div>
              <button 
                onClick={() => setIsOpen(false)}
                className="text-[#F4F0E8]/40 hover:text-[#F4F0E8] transition-colors p-2 hover:bg-white/5 rounded-full"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Chat Area */}
            <div className="flex-1 overflow-y-auto p-6 space-y-4 scrollbar-hide">
              {messages.map((msg) => (
                <motion.div
                  key={msg.id}
                  initial={{ opacity: 0, x: msg.sender === 'sierra' ? -10 : 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  className={`flex ${msg.sender === 'sierra' ? 'justify-start' : 'justify-end'}`}
                >
                  <div className={`max-w-[85%] flex gap-3 ${msg.sender === 'sierra' ? 'flex-row' : 'flex-row-reverse'}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                      msg.sender === 'sierra' 
                        ? 'bg-[#C9A24D]/10 border border-[#C9A24D]/30 text-[#C9A24D]' 
                        : 'bg-white/10 border border-white/20 text-[#F4F0E8]'
                    }`}>
                      {msg.sender === 'sierra' ? <Sparkles className="w-4 h-4" /> : <User className="w-4 h-4" />}
                    </div>
                    <div className="flex flex-col gap-2">
                      <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                        msg.sender === 'sierra'
                          ? 'bg-[#111827] text-[#F4F0E8] rounded-tl-none border border-white/5 shadow-inner'
                          : 'bg-[#C9A24D] text-[#030712] rounded-tr-none font-medium'
                      }`}>
                        {msg.text}
                      </div>
                      
                      {/* Options */}
                      {msg.sender === 'sierra' && msg.options && (
                        <div className="flex flex-wrap gap-2 mt-1">
                          {msg.options.map((opt) => (
                            <button
                              key={opt}
                              onClick={() => handleResponse(opt, opt)}
                              className="px-3 py-1.5 rounded-full border border-[#C9A24D]/30 text-[11px] text-[#C9A24D] hover:bg-[#C9A24D] hover:text-[#030712] transition-all uppercase tracking-wider"
                            >
                              {opt}
                            </button>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                </motion.div>
              ))}
              
              {isTyping && (
                <div className="flex justify-start">
                  <div className="flex gap-3 items-center bg-[#111827] px-4 py-3 rounded-2xl rounded-tl-none border border-white/5">
                    <motion.div animate={{ opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, duration: 1.5 }} className="w-1.5 h-1.5 bg-[#C9A24D] rounded-full" />
                    <motion.div animate={{ opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, duration: 1.5, delay: 0.2 }} className="w-1.5 h-1.5 bg-[#C9A24D] rounded-full" />
                    <motion.div animate={{ opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, duration: 1.5, delay: 0.4 }} className="w-1.5 h-1.5 bg-[#C9A24D] rounded-full" />
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-6 border-t border-[#C9A24D]/10 bg-black/20">
              <div className="relative group">
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && onSend()}
                  placeholder="Type your response..."
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-sm text-[#F4F0E8] placeholder-[#F4F0E8]/20 focus:outline-none focus:border-[#C9A24D]/50 transition-all group-hover:border-white/20"
                />
                <button
                  onClick={onSend}
                  className="absolute right-2 top-2 bottom-2 px-4 bg-[#C9A24D] text-[#030712] rounded-xl flex items-center justify-center hover:bg-[#F4F0E8] transition-all disabled:opacity-50"
                  disabled={!inputValue.trim()}
                >
                  <Send className="w-4 h-4" />
                </button>
              </div>
              <p className="mt-3 text-[9px] text-[#C9A24D]/40 uppercase tracking-[0.2em] text-center">
                Institutional Quality Protocol Active
              </p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Floating Toggle Button */}
      <motion.button
        whileHover={{ scale: 1.1, rotate: 5 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 rounded-full bg-[#C9A24D] text-[#030712] shadow-2xl flex items-center justify-center relative group overflow-hidden"
      >
        <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-20 transition-opacity" />
        <motion.div
          animate={isOpen ? { rotate: 90 } : { rotate: 0 }}
          transition={{ type: "spring", stiffness: 200 }}
        >
          {isOpen ? <X className="w-7 h-7" /> : <BrandLogo variant="emblem" size="sm" themeOverride="dark" />}
        </motion.div>
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-5 h-5 bg-[#F4F0E8] text-[#030712] text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-[#030712] animate-bounce">
            1
          </div>
        )}
      </motion.button>
    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Send, Sparkles, User, Brain } from 'lucide-react';

interface ChatMessage {
  id: string;
  sender: 'sierra' | 'user';
  text: string;
  isVIP?: boolean;
}

export default function SierraTerminal() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setMessages([{
        id: '1',
        sender: 'sierra',
        text: 'Sierra System Online. Awaiting client criteria to initiate matching and agent delegation protocol.'
      }]);
    }
  }, [isOpen, messages.length]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const handleSend = async () => {
    if (!inputValue.trim() || isLoading) return;
    
    const userMsg = inputValue.trim();
    setInputValue('');
    
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      sender: 'user',
      text: userMsg
    }]);
    
    setIsLoading(true);

    try {
      const response = await fetch('/api/agent/hub', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ agentId: 'SIERRA_CORE', message: userMsg })
      });
      
      const data = await response.json();
      
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        sender: 'sierra',
        text: data.response || "Error communicating with Sierra Core.",
        isVIP: data.vipAlert
      }]);
    } catch (error) {
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        sender: 'sierra',
        text: "Sierra Core is currently offline."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      <AnimatePresence>
        {!isOpen ? (
          <motion.button
            key="button"
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0, opacity: 0 }}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setIsOpen(true)}
            className="w-16 h-16 rounded-full bg-navy text-gold flex items-center justify-center shadow-2xl border-2 border-gold/30 hover:border-gold transition-colors"
          >
            <div className="absolute inset-0 bg-gold/10 rounded-full animate-ping opacity-20" />
            <Brain size={28} />
          </motion.button>
        ) : (
          <motion.div
            key="chat"
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            className="w-80 sm:w-96 h-[32rem] bg-[#0A1A3A] border border-gold/20 shadow-2xl shadow-navy/50 flex flex-col overflow-hidden"
            style={{ borderRadius: '24px' }}
          >
            {/* Header */}
            <div className="px-6 py-4 border-b border-gold/10 flex items-center justify-between bg-black/20 backdrop-blur-md">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-gold/10 flex items-center justify-center border border-gold/30">
                  <Sparkles size={18} className="text-gold" />
                </div>
                <div>
                  <h3 className="text-white font-serif font-bold text-lg leading-none m-0">Sierra</h3>
                  <span className="text-[10px] text-gold uppercase tracking-widest font-bold">Master Operational Architecture</span>
                </div>
              </div>
              <button 
                onClick={() => setIsOpen(false)}
                className="w-8 h-8 rounded-full bg-white/5 hover:bg-white/10 flex items-center justify-center text-slate-400 hover:text-white transition-colors"
              >
                <X size={16} />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6" dir="auto">
              {messages.map((msg) => (
                <motion.div 
                  key={msg.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`flex gap-3 ${msg.sender === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
                >
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                    msg.sender === 'sierra' 
                      ? 'bg-gold/10 border border-gold/30 text-gold' 
                      : 'bg-white/10 border border-white/20 text-white'
                  }`}>
                    {msg.sender === 'sierra' ? <Sparkles size={14} /> : <User size={14} />}
                  </div>
                  <div className={`px-4 py-3 text-sm ${
                    msg.sender === 'sierra'
                      ? 'bg-[#1a2b53] text-slate-200 rounded-2xl rounded-tl-sm border border-white/5'
                      : 'bg-gold text-navy font-medium rounded-2xl rounded-tr-sm'
                  }`}>
                    {msg.text}
                    {msg.isVIP && (
                      <div className="mt-3 px-3 py-1.5 bg-red-500/10 border border-red-500/30 rounded-lg flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
                        <span className="text-[10px] uppercase font-black tracking-widest text-red-500">VIP Intake Alert</span>
                      </div>
                    )}
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex gap-3 flex-row">
                   <div className="w-8 h-8 rounded-full bg-gold/10 border border-gold/30 text-gold flex items-center justify-center">
                    <Sparkles size={14} />
                  </div>
                  <div className="px-4 py-3 bg-[#1a2b53] rounded-2xl rounded-tl-sm flex items-center gap-1">
                    <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.5 }} className="w-1.5 h-1.5 rounded-full bg-gold" />
                    <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.5, delay: 0.2 }} className="w-1.5 h-1.5 rounded-full bg-gold" />
                    <motion.div animate={{ opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 1.5, delay: 0.4 }} className="w-1.5 h-1.5 rounded-full bg-gold" />
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 border-t border-gold/10 bg-black/20">
              <div className="relative flex items-center">
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Type a message..."
                  className="w-full h-12 bg-white/5 border border-white/10 rounded-full ps-5 pe-14 text-sm text-white placeholder-slate-400 focus:outline-none focus:border-gold/50 transition-colors"
                  dir="auto"
                />
                <button 
                  onClick={handleSend}
                  disabled={!inputValue.trim() || isLoading}
                  className="absolute end-2 w-8 h-8 rounded-full bg-gold text-navy flex items-center justify-center hover:bg-white disabled:opacity-50 transition-colors"
                >
                  <Send size={14} className="-ms-0.5" />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Filter, ArrowUpDown, House, MapPin, Bed, Bath, Maximize, ExternalLink, Diamond } from 'lucide-react';
import { getProperties, Property, PropertyFilters } from '@/lib/firebase/inventory';

export default function InventoryGrid() {
  const [properties, setProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<PropertyFilters>({});
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    fetchInventory();
  }, [filters]);

  const fetchInventory = async () => {
    setLoading(true);
    try {
      const data = await getProperties(filters);
      setProperties(data);
    } catch (error) {
      console.error("Error fetching inventory:", error);
    } finally {
      setLoading(false);
    }
  };

  const filteredProperties = properties.filter(p => 
    p.compound_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    p.unit_type.toLowerCase().includes(searchQuery.toLowerCase()) ||
    p.unit_code.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex flex-col gap-8 h-full">
      {/* Header & Search - Digital Curator Style */}
      <div className="flex items-center justify-between gap-6">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#D4AF37]/50" />
          <input 
            type="text" 
            placeholder="Search Global Inventory..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-[#050B14]/40 border border-[#D4AF37]/10 py-4 ps-12 pe-4 text-sm focus:outline-none focus:border-[#D4AF37]/40 transition-all font-medium rounded-xl placeholder:text-[#F4F0E8]/20"
          />
        </div>
        
        <div className="flex gap-3">
            <button className="px-6 py-4 border border-[#D4AF37]/10 flex items-center gap-2 hover:bg-[#D4AF37]/5 transition-all rounded-xl">
               <Filter className="w-4 h-4 text-[#D4AF37]" />
               <span className="text-[10px] font-black uppercase tracking-widest text-[#D4AF37]">Filters</span>
            </button>
            <button className="px-6 py-4 border border-[#D4AF37]/10 flex items-center gap-2 hover:bg-[#D4AF37]/5 transition-all rounded-xl text-[#F4F0E8]/40">
               <ArrowUpDown className="w-4 h-4" />
               <span className="text-[10px] font-black uppercase tracking-widest">Sort</span>
            </button>
        </div>
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto pe-2 scrollbar-hide">
        {loading ? (
          <div className="grid grid-cols-2 gap-8 opacity-20">
             {[1,2,3,4].map(i => (
               <div key={i} className="cinematic-surface h-[350px] animate-pulse" />
             ))}
          </div>
        ) : filteredProperties.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center border border-dashed border-[#D4AF37]/10 rounded-3xl opacity-30">
             <House className="w-16 h-16 text-[#D4AF37] mb-6" />
             <p className="text-lg font-serif tracking-widest uppercase text-[#D4AF37]">No Active Assets Found</p>
             <p className="text-[10px] uppercase tracking-[0.4em] mt-3">Adjust your neural filters or sync portal</p>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-8">
            <AnimatePresence>
              {filteredProperties.map((p) => (
                <motion.div 
                  key={p.id}
                  layout
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="cinematic-surface group cursor-pointer overflow-hidden relative"
                >
                  <div className="aspect-[16/10] bg-[#050B14] relative overflow-hidden">
                    {p.cover_image_url ? (
                      <img 
                        src={p.cover_image_url} 
                        alt={p.title_en} 
                        className="w-full h-full object-cover group-hover:scale-105 transition-all duration-[3000ms] ease-out" 
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                         <Diamond className="w-12 h-12 text-[#D4AF37]/10" />
                      </div>
                    )}
                    <div className="absolute inset-0 bg-gradient-to-t from-[#050B14] via-transparent to-transparent opacity-80" />
                    <div className="absolute top-6 left-6 z-10 px-4 py-1.5 bg-[#050B14]/80 backdrop-blur-xl border border-[#D4AF37]/20 rounded-md">
                        <span className="text-[10px] font-black text-[#D4AF37] tracking-widest uppercase">{p.unit_code}</span>
                    </div>
                  </div>

                  <div className="p-8">
                    <div className="flex items-center gap-2 mb-3">
                       <MapPin className="w-3 h-3 text-[#D4AF37]" />
                       <span className="text-[10px] font-black text-[#D4AF37]/60 uppercase tracking-[0.3em]">{p.compound_name}</span>
                    </div>
                    
                    <h4 className="text-xl font-serif mb-6 group-hover:text-[#D4AF37] transition-colors line-clamp-1 text-[#F4F0E8]">{p.title_en}</h4>
                    
                    <div className="flex items-center gap-8 mb-8 py-5 border-y border-[#F4F0E8]/5">
                       <div className="flex items-center gap-2.5">
                          <Bed className="w-4.5 h-4.5 text-[#F4F0E8]/30" />
                          <span className="text-xs font-bold text-[#F4F0E8]/80">{p.bedrooms}</span>
                       </div>
                       <div className="flex items-center gap-2.5">
                          <Bath className="w-4.5 h-4.5 text-[#F4F0E8]/30" />
                          <span className="text-xs font-bold text-[#F4F0E8]/80">{p.bathrooms}</span>
                       </div>
                       <div className="flex items-center gap-2.5">
                          <Maximize className="w-4.5 h-4.5 text-[#F4F0E8]/30" />
                          <span className="text-xs font-bold text-[#F4F0E8]/80 leading-none">{p.bua_m2} <span className="text-[8px] opacity-30">SQM</span></span>
                       </div>
                    </div>

                    <div className="flex items-center justify-between">
                       <div className="flex flex-col">
                          <span className="text-[9px] font-black text-[#F4F0E8]/30 uppercase tracking-[0.2em] leading-none mb-1.5">Asset Valuation</span>
                          <span className="text-2xl font-bold font-serif text-[#F4F0E8]">
                            {p.currency === 'USD' ? '$' : ''}{p.price.toLocaleString()} {p.currency === 'EGP' ? 'EGP' : ''}
                          </span>
                       </div>
                       <button className="w-12 h-12 flex items-center justify-center border border-[#F4F0E8]/10 rounded-full hover:border-[#D4AF37] hover:bg-[#D4AF37] hover:text-[#050B14] transition-all duration-500 group-hover:scale-110">
                          <ExternalLink className="w-5 h-5" />
                       </button>
                    </div>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>
          </div>
        )}
      </div>

      <style>{`
        .cinematic-surface {
          background: rgba(10, 22, 40, 0.6);
          backdrop-filter: blur(40px);
          border: 1px solid rgba(212, 175, 55, 0.1);
          box-shadow: 0 30px 60px rgba(0, 0, 0, 0.6);
          border-radius: 1.5rem;
          transition: all 0.6s cubic-bezier(0.23, 1, 0.32, 1);
        }
        .cinematic-surface:hover {
          border-color: rgba(212, 175, 55, 0.3);
          transform: translateY(-8px);
          box-shadow: 0 40px 80px rgba(0, 0, 0, 0.8), 0 0 20px rgba(212, 175, 55, 0.05);
        }
        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
      `}</style>
    </div>
  );
}
